#include <stdio.h>
#include <stdlib.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int n = 5;
    int *arr = malloc(n * sizeof(int)); // ★ allocation sur le tas
    if (!arr) {                          // ★ toujours vérifier NULL
        fprintf(stderr, "malloc echoue\n");
        return 1;
    }
    for (int i = 0; i < n; i++) {
        arr[i] = i + 1; // ★ remplissage
    }
    for (int i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");
    free(arr); // ★ libération obligatoire
    return 0;
}

